import{_ as t,a as e,b as i,c as d,d as n,e as r}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as p,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"IP 위치 조회와 사용자 관리","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/ip-geolocation-and-user-management.md","filePath":"ko-KR/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ko-KR/Other/ip-geolocation-and-user-management.md"};function h(m,a,u,b,g,_){return o(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="ip-위치-조회와-사용자-관리" tabindex="-1">IP 위치 조회와 사용자 관리 <a class="header-anchor" href="#ip-위치-조회와-사용자-관리" aria-label="Permalink to &quot;IP 위치 조회와 사용자 관리&quot;">​</a></h1><p>IP 위치 조회는 업로드 기록, 로그인 기기, 접속 로그 등에 남은 IP 주소를 대략적인 지역 정보로 변환합니다.</p><p>설정해 두면 관리자 화면에서 업로드 출처와 접속 위치를 더 쉽게 파악할 수 있습니다. 사용자 관리에서는 의심스러운 IP의 업로드를 차단하거나 다시 허용할 수도 있습니다.</p><h2 id="설정-위치" tabindex="-1">설정 위치 <a class="header-anchor" href="#설정-위치" aria-label="Permalink to &quot;설정 위치&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정 -&gt; IP 위치 조회</span></span></code></pre></div><p><img src="'+t+`" alt="IP 위치 조회" loading="lazy"></p><h2 id="설정-항목" tabindex="-1">설정 항목 <a class="header-anchor" href="#설정-항목" aria-label="Permalink to &quot;설정 항목&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>IP 위치 표시 언어</td><td>한국어, 영어, 중국어 등 표시 언어 선택</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service 계정 ID</td></tr><tr><td>MaxMind License Key</td><td>MaxMind 라이선스 키</td></tr><tr><td>Tencent Map Key</td><td>중국 지역 주소 표시에 강한 Tencent 위치 서비스 키</td></tr><tr><td>ipapi Key</td><td>다국어 IP 위치 조회를 지원하는 APILayer ipapi 키</td></tr></tbody></table><p>필요한 서비스만 설정하면 됩니다. 아무 키를 넣지 않아도 내장 무료 소스를 시도하지만, 안정성, 언어 지원, 정확도는 직접 설정한 서비스가 더 좋습니다.</p><h2 id="한국어-표시로-쓰려면" tabindex="-1">한국어 표시로 쓰려면 <a class="header-anchor" href="#한국어-표시로-쓰려면" aria-label="Permalink to &quot;한국어 표시로 쓰려면&quot;">​</a></h2><p>표시 언어를 한국어로 두고 MaxMind 또는 ipapi를 설정하는 방식이 무난합니다. 중국 본토 IP를 더 자세히 보고 싶다면 Tencent Map Key를 추가로 설정합니다.</p><h2 id="maxmind-설정" tabindex="-1">MaxMind 설정 <a class="header-anchor" href="#maxmind-설정" aria-label="Permalink to &quot;MaxMind 설정&quot;">​</a></h2><p>MaxMind에는 다음 두 값이 필요합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>대시보드에서 Account ID를 확인하고, License Keys 페이지에서 키를 만든 뒤 ImgBed에 붙여 넣습니다.</p><p><img src="`+e+'" alt="MaxMind 키 설정" loading="lazy"></p><h2 id="ipapi-설정" tabindex="-1">ipapi 설정 <a class="header-anchor" href="#ipapi-설정" aria-label="Permalink to &quot;ipapi 설정&quot;">​</a></h2><p>ipapi 콘솔에서 API Key를 복사해 ImgBed의 <code>ipapi Key</code> 항목에 붙여 넣습니다.</p><p><img src="'+i+'" alt="ipapi 설정" loading="lazy"></p><h2 id="사용자-관리에서-확인할-내용" tabindex="-1">사용자 관리에서 확인할 내용 <a class="header-anchor" href="#사용자-관리에서-확인할-내용" aria-label="Permalink to &quot;사용자 관리에서 확인할 내용&quot;">​</a></h2><p>사용자 관리는 관리자 화면 상단에서 열 수 있습니다.</p><p><img src="'+d+'" alt="사용자 관리" loading="lazy"></p><p>IP별로 다음 정보를 확인합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>IP</td><td>업로드 출처 IP</td></tr><tr><td>위치</td><td>IP로 추정한 지역</td></tr><tr><td>총 업로드 용량</td><td>해당 IP가 업로드한 전체 용량</td></tr><tr><td>업로드 횟수</td><td>업로드한 파일 수</td></tr><tr><td>업로드 허용</td><td>끄면 이후 해당 IP의 업로드를 차단</td></tr></tbody></table><p>왼쪽 화살표를 열면 해당 IP가 업로드한 파일 목록을 볼 수 있습니다. 파일명, 미리보기, 파일 크기, 심사 결과, 상태, 업로드 시각을 확인한 뒤 차단 여부를 판단합니다.</p><p><img src="'+n+'" alt="고급 필터" loading="lazy"></p><h2 id="운영-팁" tabindex="-1">운영 팁 <a class="header-anchor" href="#운영-팁" aria-label="Permalink to &quot;운영 팁&quot;">​</a></h2><ul><li>의심스러운 IP는 먼저 파일 내용을 확인한 뒤 업로드 허용을 끕니다.</li><li>최근 업로드, 고빈도 업로드, 대용량 업로드는 검색과 정렬로 빠르게 찾을 수 있습니다.</li><li>위치 정보는 추정값입니다. 최종 판단 기준이 아니라 참고 자료로 활용하세요.</li></ul><p><img src="'+r+'" alt="모바일 표시" loading="lazy"></p>',29)])])}const M=p(c,[["render",h]]);export{I as __pageData,M as default};
